  ('police-f3743df6-moex-00370', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '依廢棄物清理法規定，在指定清除地區內拋棄紙屑者，處新臺幣（下同）1,200元以上6,000元以 下罰鍰。若17歲的甲違反前揭規定，主管機關乙欲減輕其處罰時，乙得於下列何種罰鍰額度內 行使裁量權？', '["600元以上3,000元以下", "400元以上2,000元以下", "300元以上1,500元以下", "240元以上1,200元以下"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00371', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '關於行政罰裁處權之時效規定，下列何者錯誤？', '["行政罰之裁處權，因三年期間之經過而消滅", "裁處權時效自違反行政法上義務之行為終了時起算", "因免刑而應處以行政罰者，裁處權時效自免刑之裁判確定日起算", "行政罰之裁處因行政訴訟經撤銷而須另為裁處者，裁處權時效自原裁處被判決撤銷之日起算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00372', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '下列有關行政執行之敘述，何者正確？', '["義務人死亡時，得對其繼承人之財產為強制執行", "日間開始執行者，於夜間到來時，應停止執行", "義務人對於執行方法聲明異議，其就主管機關所為聲明異議之決定，不得提起救濟", "義務人懷胎5月以上或生產後2月未滿者，不得管收"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00373', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '人民不履行行政法上之義務，於行政執行時得處怠金者，為下列何種情形？', '["命甲自行拆除違章建築，而甲不自行拆除", "命乙公司停止營業，而乙公司不為停止", "通知丙限期補繳稅款，而丙逾期仍不繳納", "命丁撲殺其已得傳染病之犬隻，而丁不為撲殺"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00374', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '下列何者非行政執行機關核發禁止為特定投資命令之要件？', '["義務人為自然人", "義務人之滯欠合計達一定金額", "已發現之財產足以清償其所負義務", "義務人之生活逾越一般人通常程度者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00375', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '關於行政執行之拘提，下列敘述何者正確？', '["義務人顯有逃匿之虞者，執行員得逕行拘提之", "義務人經拘提到場，法院應即為必要之調查", "拘提後，義務人已履行全部義務，應即釋放之", "義務人經拘提到場，符合管收要件者，應將之送交管收所"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00376', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '關於訴願期間之敘述，下列何者正確？', '["訴願之提起，應自行政處分達到之日起算三十日內為之", "利害關係人提起訴願者，自行政處分公告期滿後，已逾一年者，不得提起", "訴願之提起，以受理訴願機關收受訴願書之日期為準", "誤向原行政處分機關以外之機關提起訴願者，以該機關知悉之日，視為提起訴願之日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00377', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '關於訴願參加，下列敘述何者錯誤？', '["申請參加訴願，應以書面向受理訴願機關為之", "通知參加訴願，應記載法定事項送達於參加人", "通知參加訴願應通知訴願人以書面陳述意見", "訴願決定對於經受理訴願機關通知其參加而未參加者亦有效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00378', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '關於訴願代理之敘述，下列何者錯誤？', '["委任二人以上為訴願代理人，縱約定不得單獨代理，訴願代理人仍得單獨代理", "訴願代理人事實上之陳述，經到場之訴願人本人即時更正者，不生效力", "訴願代理權因訴願人本人死亡、破產或喪失訴願能力而消滅", "訴願委任之解除，應由訴願人以書面通知受理訴願機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00379', 'police-f3743df6', 'police-f3743df6-moex-111-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '甲針對下列何種事件提起行政訴訟，有起訴期間之限制？', '["甲請求與其締結行政契約之機關履行義務", "甲申請建造執照而主管機關未予回覆", "甲認為原行政處分無效", "甲認為主管機關就其徵收案件未依限補償，原徵收處分已失其效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "62a2786c5c88", "answer_pdf_sha1": "4821181f113d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL)
